public static ETGAgreementTrackingPurchReportController construct()
{
    return new ETGAgreementTrackingPurchReportController();
}

public static void main(Args _args)
{
    ETGAgreementTrackingPurchReportController controller = ETGAgreementTrackingPurchReportController::construct();
    controller.parmArgs(_args);

    controller.parmReportName(ssrsReportStr(ETGAgreementTrackingPurchaseReport, Report));
    controller.startOperation();
}

public void preRunModifyContract()
{

    ETGAgreementTrackingPurchReportContract contract = this.parmReportContract().parmRdpContract() as ETGAgreementTrackingPurchReportContract;
    this.parmReportContract().parmReportName(this.getSelectedReportName(contract));

    super();

}

private str getSelectedReportName(ETGAgreementTrackingPurchReportContract _contract)
{
    str reportNameLocal;
    if (_contract.parmQty())
    {
        reportNameLocal = ssrsReportStr(ETGAgreementTrackingPurchaseReport, ReportQual);
    }
    else
    {
        reportNameLocal = ssrsReportStr(ETGAgreementTrackingPurchaseReport, Report);
    }
    return reportNameLocal;
}
